/**
 * @summary Gets a patient's current context snapshot (rebuilds if stale or missing)
 */
export const getSnapshot = (
    patientId: string,
 options?: SecondParameter<typeof apiClient>,signal?: AbortSignal
) => {
      
      
      return apiClient<PatientContextSnapshot>(
      {url: `/api/v1/clinical-chat/context/snapshot/${patientId}`, method: 'GET', signal
    },
      options);
    }
  



export const getGetSnapshotQueryKey = (patientId?: string,) => {
    return [
    `/api/v1/clinical-chat/context/snapshot/${patientId}`
    ] as const;
    }

    
